import { useState } from "react";

const GridSlider = () => {
    const [activeSlide, setActiveSlide] = useState(0);

    const slides = [
        {
            main: "/api/placeholder/800/400"
            , items: [
                { image : "https://flowbite.s3.amazonaws.com/docs/gallery/square/image-1.jpg", text : 국내도서 }
                , { image : "https://flowbite.s3.amazonaws.com/docs/gallery/square/image-2.jpg", text : 해외도서}
                , { image : "https://flowbite.s3.amazonaws.com/docs/gallery/square/image-3.jpg", text : 굿즈}
                , {image : "https://flowbite.s3.amazonaws.com/docs/gallery/square/image-4.jpg", text : 이벤트}
            // image : "https://flowbite.s3.amazonaws.com/docs/gallery/square/image-5.jpg" alt=""/>
                ],
            },
        {}
    ]

    const handleItemClick = (index) => {
        setActiveSlide(index);
    };

    return(
        <div className="relative w-full overflow-hidden">
            <div className="flex transition-transform duration-300 ease-in-out" style={{transform: `translateX(-${activeSlide * 100}%)`}}>
                {slides.map((slide, index) => (
                    <div key={index} className="w-full flex-shrink-0">
                        <div className="grid gap-4">
                            <div>
                                <img className="h-auto w-full rounded-lg" src={slide.main} alt={`Slide ${index + 1} main`}/>
                            </div>
                        </div>
                    </div>
                ))}
            </div>
            <div className="grid grid-cols-4 gap-4 mt-4">
                {slides[0].items.map((item, itemIndex) => (
                    <button key={itemIndex} 
                        onClick={() => handleItemClick(itemIndex)} 
                        className="relative w-full h-24 rounded-lg overflow-hidden focus:outline-none focus:ring-2 focus:ring-blue-300"
                        style={{
                            backgroundImage : `url(${item.image})`
                            , backgroundSize : 'cover'
                            , backgroundPosition : 'center'
                        }}
                    >
                        <div className="absolute inset-0 bg-gray-800 bg-opacity-50 flex items-center justify-center">
                            <span className="text-white text-lg font-bold">{item.text}</span>
                        </div>
                    </button>
                ))}
            </div>
        </div>
    )
};

export default GridSlider;
